body:
working `test.sv`:

```verilog
interface my_if ();
  logic sig;
  modport master ( output sig );
  modport slave ( input sig );
endinterface : my_if

package my_pkg;
  typedef virtual my_if my_vif;
  function void my_func;
  input my_vif in_vif;
  begin
    in_vif.sig = 1'b1;
  end
  endfunction : my_func
endpackage : my_pkg

module test ();
  import my_pkg::*;

  logic clk;
  my_if sif();

  dut DUT (.*);

  initial begin : clock_generation
    clk = 0;
    forever #(5) clk = ~clk;
  end : clock_generation

  initial begin
    repeat (4) @(posedge clk);
    my_func(sif);
    $finish;
  end
endmodule : test

module dut (input logic clk, my_if.slave sif);
  always_ff @( posedge clk ) begin
    if (sif.sig == 1'b1) $display("Hello World");
  end
endmodule : dut
```

broken `test.sv` :

```verilog
interface my_if ();
  logic sig;
  modport master ( output sig );
  modport slave ( input sig );
endinterface : my_if

package my_pkg;
  typedef virtual my_if my_vif;
  function void my_func;
  input my_vif in_vif;
  begin
    in_vif.sig = 1'b1;
  end
  endfunction : my_func
endpackage : my_pkg

module test ();
  import my_pkg::*;

  logic clk;
  my_if sif[2] ();

  dut DUT (.*);

  initial begin : clock_generation
    clk = 0;
    forever #(5) clk = ~clk;
  end : clock_generation

  initial begin
    repeat (4) @(posedge clk);
    my_func(sif[0]);
    my_func(sif[1]);
    $finish;
  end
endmodule : test

module dut (input logic clk, my_if.slave sif[2]);
generate
  genvar i;
for (i=0; i<2; i++) begin
  always_ff @( posedge clk ) begin
    if (sif[i].sig == 1'b1) $display("Hello World %0d", i);
  end
end
endgenerate
endmodule : dut
```
